pub const PYTHON_IDENTIFIERS_QUERY: &str = include_str!("queries/python/identifiers.scm");
pub const RUST_IDENTIFIERS_QUERY: &str = include_str!("queries/rust/identifiers.scm");

pub fn get_query_for_language(lang: &crate::polyglot_traits::LanguageOrigin) -> Option<&'static str> {
    match lang {
        crate::polyglot_traits::LanguageOrigin::Python => Some(PYTHON_IDENTIFIERS_QUERY),
        crate::polyglot_traits::LanguageOrigin::Rust => Some(RUST_IDENTIFIERS_QUERY),
        _ => None,
    }
}
